void JSCryptoHasher::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSCryptoHasher*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_algorithmValue = thisObject->m_algorithm.get()) {
  if (m_algorithmValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "algorithm"_s);
    analyzer.analyzePropertyNameEdge(cell, m_algorithmValue.asCell(), id.impl());
  }
}
}

