template<typename Visitor>
void JSCryptoHasher::visitAdditionalChildrenInGCThread(Visitor& visitor)
{
  JSCryptoHasher* thisObject = this;
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    
    visitor.append(thisObject->m_algorithms);
visitor.append(thisObject->m_algorithm);
    
    
}

DEFINE_VISIT_ADDITIONAL_CHILDREN_IN_GC_THREAD(JSCryptoHasher);

