void JSDebugHTTPSServer::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSDebugHTTPSServer*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_routeListValue = thisObject->m_routeList.get()) {
  if (m_routeListValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "routeList"_s);
    analyzer.analyzePropertyNameEdge(cell, m_routeListValue.asCell(), id.impl());
  }
}
  
if (JSValue m_addressValue = thisObject->m_address.get()) {
  if (m_addressValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "address"_s);
    analyzer.analyzePropertyNameEdge(cell, m_addressValue.asCell(), id.impl());
  }
}
  
if (JSValue m_hostnameValue = thisObject->m_hostname.get()) {
  if (m_hostnameValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "hostname"_s);
    analyzer.analyzePropertyNameEdge(cell, m_hostnameValue.asCell(), id.impl());
  }
}
  
if (JSValue m_idValue = thisObject->m_id.get()) {
  if (m_idValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "id"_s);
    analyzer.analyzePropertyNameEdge(cell, m_idValue.asCell(), id.impl());
  }
}
  
if (JSValue m_urlValue = thisObject->m_url.get()) {
  if (m_urlValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "url"_s);
    analyzer.analyzePropertyNameEdge(cell, m_urlValue.asCell(), id.impl());
  }
}
}



