void JSDocType::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSDocType*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_nameValue = thisObject->m_name.get()) {
  if (m_nameValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "name"_s);
    analyzer.analyzePropertyNameEdge(cell, m_nameValue.asCell(), id.impl());
  }
}
  
if (JSValue m_publicIdValue = thisObject->m_publicId.get()) {
  if (m_publicIdValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "publicId"_s);
    analyzer.analyzePropertyNameEdge(cell, m_publicIdValue.asCell(), id.impl());
  }
}
  
if (JSValue m_systemIdValue = thisObject->m_systemId.get()) {
  if (m_systemIdValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "systemId"_s);
    analyzer.analyzePropertyNameEdge(cell, m_systemIdValue.asCell(), id.impl());
  }
}
}



JSObject* JSDocType::createPrototype(VM& vm, JSDOMGlobalObject* globalObject)
{
    auto *structure = JSDocTypePrototype::createStructure(vm, globalObject, globalObject->objectPrototype());
    structure->setMayBePrototype(true);
    return JSDocTypePrototype::create(vm, globalObject, structure);
}

