void JSExpectObjectContaining::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSExpectObjectContaining*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_objectValueValue = thisObject->m_objectValue.get()) {
  if (m_objectValueValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "objectValue"_s);
    analyzer.analyzePropertyNameEdge(cell, m_objectValueValue.asCell(), id.impl());
  }
}
}



