template<typename Visitor>
void JSExpectObjectContaining::visitAdditionalChildrenInGCThread(Visitor& visitor)
{
  JSExpectObjectContaining* thisObject = this;
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    visitor.append(thisObject->m_objectValue);
    
    
    
}

DEFINE_VISIT_ADDITIONAL_CHILDREN_IN_GC_THREAD(JSExpectObjectContaining);

