void JSExpectStringContaining::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSExpectStringContaining*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_stringValueValue = thisObject->m_stringValue.get()) {
  if (m_stringValueValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "stringValue"_s);
    analyzer.analyzePropertyNameEdge(cell, m_stringValueValue.asCell(), id.impl());
  }
}
}



