void JSFFI::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSFFI*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_symbolsValueValue = thisObject->m_symbolsValue.get()) {
  if (m_symbolsValueValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "symbolsValue"_s);
    analyzer.analyzePropertyNameEdge(cell, m_symbolsValueValue.asCell(), id.impl());
  }
}
  
if (JSValue m_symbolsValueValue = thisObject->m_symbolsValue.get()) {
  if (m_symbolsValueValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "symbols"_s);
    analyzer.analyzePropertyNameEdge(cell, m_symbolsValueValue.asCell(), id.impl());
  }
}
}



