void JSFileInternalReadableStreamSource::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSFileInternalReadableStreamSource*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_pendingPromiseValue = thisObject->m_pendingPromise.get()) {
  if (m_pendingPromiseValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "pendingPromise"_s);
    analyzer.analyzePropertyNameEdge(cell, m_pendingPromiseValue.asCell(), id.impl());
  }
}
  
if (JSValue m_onCloseCallbackValue = thisObject->m_onCloseCallback.get()) {
  if (m_onCloseCallbackValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "onCloseCallback"_s);
    analyzer.analyzePropertyNameEdge(cell, m_onCloseCallbackValue.asCell(), id.impl());
  }
}
  
if (JSValue m_onDrainCallbackValue = thisObject->m_onDrainCallback.get()) {
  if (m_onDrainCallbackValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "onDrainCallback"_s);
    analyzer.analyzePropertyNameEdge(cell, m_onDrainCallbackValue.asCell(), id.impl());
  }
}
}



