  JSC::JSValue decodedValue = JSC::JSValue::decode(value);
  if (decodedValue.isEmpty() || !decodedValue.isCell())
      return nullptr;

  JSC::JSCell* cell = decodedValue.asCell();
  JSFileSystemRouter* object = JSC::jsDynamicCast<JSFileSystemRouter*>(cell);

