void JSFileSystemRouter::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSFileSystemRouter*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_originValue = thisObject->m_origin.get()) {
  if (m_originValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "origin"_s);
    analyzer.analyzePropertyNameEdge(cell, m_originValue.asCell(), id.impl());
  }
}
  
if (JSValue m_routesValue = thisObject->m_routes.get()) {
  if (m_routesValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "routes"_s);
    analyzer.analyzePropertyNameEdge(cell, m_routesValue.asCell(), id.impl());
  }
}
  
if (JSValue m_styleValue = thisObject->m_style.get()) {
  if (m_styleValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "style"_s);
    analyzer.analyzePropertyNameEdge(cell, m_styleValue.asCell(), id.impl());
  }
}
}

