void JSGlobPrototype::finishCreation(JSC::VM& vm, JSC::JSGlobalObject* globalObject)
{
    Base::finishCreation(vm);
    reifyStaticProperties(vm, JSGlob::info(), JSGlobPrototypeTableValues, *this);
    this->putDirect(vm, WebCore::clientData(vm)->builtinNames().pullPrivateName(), JSFunction::create(vm, globalObject, 1, String("__scan"_s), GlobPrototype____scanCallback, ImplementationVisibility::Private), PropertyAttribute::ReadOnly | PropertyAttribute::DontEnum | 0);
    this->putDirect(vm, WebCore::clientData(vm)->builtinNames().resolveSyncPrivateName(), JSFunction::create(vm, globalObject, 1, String("__scanSync"_s), GlobPrototype____scanSyncCallback, ImplementationVisibility::Private), PropertyAttribute::ReadOnly | PropertyAttribute::DontEnum | 0);
    JSC_TO_STRING_TAG_WITHOUT_TRANSITION();
}

void JSGlobConstructor::finishCreation(VM& vm, JSC::JSGlobalObject* globalObject, JSGlobPrototype* prototype)
{
    Base::finishCreation(vm, 0, "Glob"_s, PropertyAdditionMode::WithoutStructureTransition);
    
    putDirectWithoutTransition(vm, vm.propertyNames->prototype, prototype, PropertyAttribute::DontEnum | PropertyAttribute::DontDelete | PropertyAttribute::ReadOnly);
    ASSERT(inherits(info()));
}

