template<typename Visitor>
void JSGlob::visitAdditionalChildrenInGCThread(Visitor& visitor)
{
  JSGlob* thisObject = this;
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    
    
    
    visitor.addOpaqueRoot(this->wrapped());
}

