JSMatchedRoute::~JSMatchedRoute()
{
    if (m_ctx) [[likely]] {
        MatchedRouteClass__finalize(m_ctx);
    }
}

size_t JSMatchedRoute::memoryCost(void* ptr) {
  return ptr ? MatchedRoute__ZigStructSize : 0;
}
  size_t JSMatchedRoute::estimatedSize(JSC::JSCell* cell, JSC::VM& vm) {
  auto* thisObject = jsCast<JSMatchedRoute*>(cell);
  auto* wrapped = thisObject->wrapped();
  return Base::estimatedSize(cell, vm) + JSMatchedRoute::memoryCost(wrapped);
}

