void JSMySQLQuery::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSMySQLQuery*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_pendingValueValue = thisObject->m_pendingValue.get()) {
  if (m_pendingValueValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "pendingValue"_s);
    analyzer.analyzePropertyNameEdge(cell, m_pendingValueValue.asCell(), id.impl());
  }
}
  
if (JSValue m_targetValue = thisObject->m_target.get()) {
  if (m_targetValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "target"_s);
    analyzer.analyzePropertyNameEdge(cell, m_targetValue.asCell(), id.impl());
  }
}
  
if (JSValue m_columnsValue = thisObject->m_columns.get()) {
  if (m_columnsValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "columns"_s);
    analyzer.analyzePropertyNameEdge(cell, m_columnsValue.asCell(), id.impl());
  }
}
  
if (JSValue m_bindingValue = thisObject->m_binding.get()) {
  if (m_bindingValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "binding"_s);
    analyzer.analyzePropertyNameEdge(cell, m_bindingValue.asCell(), id.impl());
  }
}
}

