template<typename Visitor>
void JSMySQLQuery::visitChildrenImpl(JSCell* cell, Visitor& visitor)
{
    JSMySQLQuery* thisObject = jsCast<JSMySQLQuery*>(cell);
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    Base::visitChildren(thisObject, visitor);
    if (auto* ptr = thisObject->wrapped()) {
            auto size = MySQLQuery__estimatedSize(ptr);
visitor.reportExtraMemoryVisited(size);
}
    thisObject->visitAdditionalChildrenInGCThread<Visitor>(visitor);
}

DEFINE_VISIT_CHILDREN(JSMySQLQuery);



template<typename Visitor>
void JSMySQLQuery::visitAdditionalChildrenInGCThread(Visitor& visitor)
{
  JSMySQLQuery* thisObject = this;
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    visitor.append(thisObject->m_pendingValue);
visitor.append(thisObject->m_target);
visitor.append(thisObject->m_columns);
visitor.append(thisObject->m_binding);
    
    
    
}

DEFINE_VISIT_ADDITIONAL_CHILDREN_IN_GC_THREAD(JSMySQLQuery);

template<typename Visitor>
void JSMySQLQuery::visitOutputConstraintsImpl(JSCell *cell, Visitor& visitor)
{
    JSMySQLQuery* thisObject = jsCast<JSMySQLQuery*>(cell);
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    thisObject->visitAdditionalChildrenInGCThread<Visitor>(visitor);
}

