{
    if (m_ctx) [[likely]] {
        NativeZstdClass__finalize(m_ctx);
    }
}

size_t JSNativeZstd::memoryCost(void* ptr) {
  return ptr ? NativeZstd__estimatedSize(ptr) : 0;
}
  size_t JSNativeZstd::estimatedSize(JSC::JSCell* cell, JSC::VM& vm) {
  auto* thisObject = jsCast<JSNativeZstd*>(cell);
  auto* wrapped = thisObject->wrapped();
  return Base::estimatedSize(cell, vm) + JSNativeZstd::memoryCost(wrapped);
}

