void JSPostgresSQLConnection::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSPostgresSQLConnection*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_onconnectValue = thisObject->m_onconnect.get()) {
  if (m_onconnectValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "onconnect"_s);
    analyzer.analyzePropertyNameEdge(cell, m_onconnectValue.asCell(), id.impl());
  }
}
  
if (JSValue m_oncloseValue = thisObject->m_onclose.get()) {
  if (m_oncloseValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "onclose"_s);
    analyzer.analyzePropertyNameEdge(cell, m_oncloseValue.asCell(), id.impl());
  }
}
  
if (JSValue m_queriesValue = thisObject->m_queries.get()) {
  if (m_queriesValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "queries"_s);
    analyzer.analyzePropertyNameEdge(cell, m_queriesValue.asCell(), id.impl());
  }
}
}

