void JSRedisClientConstructor::finishCreation(VM& vm, JSC::JSGlobalObject* globalObject, JSRedisClientPrototype* prototype)
{
    Base::finishCreation(vm, 0, "RedisClient"_s, PropertyAdditionMode::WithoutStructureTransition);
    
    putDirectWithoutTransition(vm, vm.propertyNames->prototype, prototype, PropertyAttribute::DontEnum | PropertyAttribute::DontDelete | PropertyAttribute::ReadOnly);
    ASSERT(inherits(info()));
}

