void JSResolveMessage::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSResolveMessage*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_codeValue = thisObject->m_code.get()) {
  if (m_codeValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "code"_s);
    analyzer.analyzePropertyNameEdge(cell, m_codeValue.asCell(), id.impl());
  }
}
  
if (JSValue m_importKindValue = thisObject->m_importKind.get()) {
  if (m_importKindValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "importKind"_s);
    analyzer.analyzePropertyNameEdge(cell, m_importKindValue.asCell(), id.impl());
  }
}
  
if (JSValue m_levelValue = thisObject->m_level.get()) {
  if (m_levelValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "level"_s);
    analyzer.analyzePropertyNameEdge(cell, m_levelValue.asCell(), id.impl());
  }
}
  
if (JSValue m_messageValue = thisObject->m_message.get()) {
  if (m_messageValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "message"_s);
    analyzer.analyzePropertyNameEdge(cell, m_messageValue.asCell(), id.impl());
  }
}
  
if (JSValue m_positionValue = thisObject->m_position.get()) {
  if (m_positionValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "position"_s);
    analyzer.analyzePropertyNameEdge(cell, m_positionValue.asCell(), id.impl());
  }
}
  
if (JSValue m_referrerValue = thisObject->m_referrer.get()) {
  if (m_referrerValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "referrer"_s);
    analyzer.analyzePropertyNameEdge(cell, m_referrerValue.asCell(), id.impl());
  }
}
  
if (JSValue m_specifierValue = thisObject->m_specifier.get()) {
  if (m_specifierValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "specifier"_s);
    analyzer.analyzePropertyNameEdge(cell, m_specifierValue.asCell(), id.impl());
  }
}
}

