void JSResumableFetchSink::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSResumableFetchSink*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_ondrainValue = thisObject->m_ondrain.get()) {
  if (m_ondrainValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "ondrain"_s);
    analyzer.analyzePropertyNameEdge(cell, m_ondrainValue.asCell(), id.impl());
  }
}
  
if (JSValue m_oncancelValue = thisObject->m_oncancel.get()) {
  if (m_oncancelValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "oncancel"_s);
    analyzer.analyzePropertyNameEdge(cell, m_oncancelValue.asCell(), id.impl());
  }
}
  
if (JSValue m_streamValue = thisObject->m_stream.get()) {
  if (m_streamValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "stream"_s);
    analyzer.analyzePropertyNameEdge(cell, m_streamValue.asCell(), id.impl());
  }
}
}

