template<typename Visitor>
void JSResumableFetchSink::visitAdditionalChildrenInGCThread(Visitor& visitor)
{
  JSResumableFetchSink* thisObject = this;
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    visitor.append(thisObject->m_ondrain);
visitor.append(thisObject->m_oncancel);
visitor.append(thisObject->m_stream);
    
    
    
}

DEFINE_VISIT_ADDITIONAL_CHILDREN_IN_GC_THREAD(JSResumableFetchSink);

