void JSResumableFetchSink::visitOutputConstraintsImpl(JSCell *cell, Visitor& visitor)
{
    JSResumableFetchSink* thisObject = jsCast<JSResumableFetchSink*>(cell);
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    thisObject->visitAdditionalChildrenInGCThread<Visitor>(visitor);
}

