void JSS3Stat::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSS3Stat*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_etagValue = thisObject->m_etag.get()) {
  if (m_etagValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "etag"_s);
    analyzer.analyzePropertyNameEdge(cell, m_etagValue.asCell(), id.impl());
  }
}
  
if (JSValue m_lastModifiedValue = thisObject->m_lastModified.get()) {
  if (m_lastModifiedValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "lastModified"_s);
    analyzer.analyzePropertyNameEdge(cell, m_lastModifiedValue.asCell(), id.impl());
  }
}
  
if (JSValue m_sizeValue = thisObject->m_size.get()) {
  if (m_sizeValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "size"_s);
    analyzer.analyzePropertyNameEdge(cell, m_sizeValue.asCell(), id.impl());
  }
}
  
if (JSValue m_typeValue = thisObject->m_type.get()) {
  if (m_typeValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "type"_s);
    analyzer.analyzePropertyNameEdge(cell, m_typeValue.asCell(), id.impl());
  }
}
}

