template<typename Visitor>
void JSS3Stat::visitChildrenImpl(JSCell* cell, Visitor& visitor)
{
    JSS3Stat* thisObject = jsCast<JSS3Stat*>(cell);
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    Base::visitChildren(thisObject, visitor);
    
    thisObject->visitAdditionalChildrenInGCThread<Visitor>(visitor);
}

DEFINE_VISIT_CHILDREN(JSS3Stat);



template<typename Visitor>
void JSS3Stat::visitAdditionalChildrenInGCThread(Visitor& visitor)
{
  JSS3Stat* thisObject = this;
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    
    visitor.append(thisObject->m_etag);
visitor.append(thisObject->m_lastModified);
visitor.append(thisObject->m_size);
visitor.append(thisObject->m_type);
    
    
}

DEFINE_VISIT_ADDITIONAL_CHILDREN_IN_GC_THREAD(JSS3Stat);

template<typename Visitor>
void JSS3Stat::visitOutputConstraintsImpl(JSCell *cell, Visitor& visitor)
{
    JSS3Stat* thisObject = jsCast<JSS3Stat*>(cell);
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    thisObject->visitAdditionalChildrenInGCThread<Visitor>(visitor);
}

DEFINE_VISIT_OUTPUT_CONSTRAINTS(JSS3Stat);

