{
    if (m_ctx) [[likely]] {
        SHA1Class__finalize(m_ctx);
    }
}

size_t JSSHA1::memoryCost(void* ptr) {
  return ptr ? SHA1__ZigStructSize : 0;
}
  size_t JSSHA1::estimatedSize(JSC::JSCell* cell, JSC::VM& vm) {
  auto* thisObject = jsCast<JSSHA1*>(cell);
  auto* wrapped = thisObject->wrapped();
  return Base::estimatedSize(cell, vm) + JSSHA1::memoryCost(wrapped);
}

