void JSServerWebSocket::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSServerWebSocket*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_socketValue = thisObject->m_socket.get()) {
  if (m_socketValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "socket"_s);
    analyzer.analyzePropertyNameEdge(cell, m_socketValue.asCell(), id.impl());
  }
}
  
if (JSValue m_dataValue = thisObject->m_data.get()) {
  if (m_dataValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "data"_s);
    analyzer.analyzePropertyNameEdge(cell, m_dataValue.asCell(), id.impl());
  }
}
  
if (JSValue m_remoteAddressValue = thisObject->m_remoteAddress.get()) {
  if (m_remoteAddressValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "remoteAddress"_s);
    analyzer.analyzePropertyNameEdge(cell, m_remoteAddressValue.asCell(), id.impl());
  }
}
}

