void JSShellInterpreter::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSShellInterpreter*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_resolveValue = thisObject->m_resolve.get()) {
  if (m_resolveValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "resolve"_s);
    analyzer.analyzePropertyNameEdge(cell, m_resolveValue.asCell(), id.impl());
  }
}
  
if (JSValue m_rejectValue = thisObject->m_reject.get()) {
  if (m_rejectValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "reject"_s);
    analyzer.analyzePropertyNameEdge(cell, m_rejectValue.asCell(), id.impl());
  }
}
}



