template<typename Visitor>
void JSShellInterpreter::visitChildrenImpl(JSCell* cell, Visitor& visitor)
{
    JSShellInterpreter* thisObject = jsCast<JSShellInterpreter*>(cell);
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    Base::visitChildren(thisObject, visitor);
    if (auto* ptr = thisObject->wrapped()) {
            auto size = ShellInterpreter__estimatedSize(ptr);
visitor.reportExtraMemoryVisited(size);
}
    thisObject->visitAdditionalChildrenInGCThread<Visitor>(visitor);
}

DEFINE_VISIT_CHILDREN(JSShellInterpreter);



template<typename Visitor>
void JSShellInterpreter::visitAdditionalChildrenInGCThread(Visitor& visitor)
{
  JSShellInterpreter* thisObject = this;
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    visitor.append(thisObject->m_resolve);
visitor.append(thisObject->m_reject);
    
    for (auto& value : thisObject->jsvalueArray) { visitor.append(value); }
    visitor.addOpaqueRoot(this->wrapped());
}

DEFINE_VISIT_ADDITIONAL_CHILDREN_IN_GC_THREAD(JSShellInterpreter);

template<typename Visitor>
void JSShellInterpreter::visitOutputConstraintsImpl(JSCell *cell, Visitor& visitor)
{
    JSShellInterpreter* thisObject = jsCast<JSShellInterpreter*>(cell);
    ASSERT_GC_OBJECT_INHERITS(thisObject, info());
    thisObject->visitAdditionalChildrenInGCThread<Visitor>(visitor);
}

DEFINE_VISIT_OUTPUT_CONSTRAINTS(JSShellInterpreter);

