void JSSocketAddress::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSSocketAddress*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_addressValue = thisObject->m_address.get()) {
  if (m_addressValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "address"_s);
    analyzer.analyzePropertyNameEdge(cell, m_addressValue.asCell(), id.impl());
  }
}
  
if (JSValue m_familyValue = thisObject->m_family.get()) {
  if (m_familyValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "family"_s);
    analyzer.analyzePropertyNameEdge(cell, m_familyValue.asCell(), id.impl());
  }
}
}

