void JSSourceMap::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSSourceMap*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_lineLengthsValue = thisObject->m_lineLengths.get()) {
  if (m_lineLengthsValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "lineLengths"_s);
    analyzer.analyzePropertyNameEdge(cell, m_lineLengthsValue.asCell(), id.impl());
  }
}
  
if (JSValue m_payloadValue = thisObject->m_payload.get()) {
  if (m_payloadValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "payload"_s);
    analyzer.analyzePropertyNameEdge(cell, m_payloadValue.asCell(), id.impl());
  }
}
}

