void JSTerminal::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSTerminal*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_dataValue = thisObject->m_data.get()) {
  if (m_dataValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "data"_s);
    analyzer.analyzePropertyNameEdge(cell, m_dataValue.asCell(), id.impl());
  }
}
  
if (JSValue m_drainValue = thisObject->m_drain.get()) {
  if (m_drainValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "drain"_s);
    analyzer.analyzePropertyNameEdge(cell, m_drainValue.asCell(), id.impl());
  }
}
  
if (JSValue m_exitValue = thisObject->m_exit.get()) {
  if (m_exitValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "exit"_s);
    analyzer.analyzePropertyNameEdge(cell, m_exitValue.asCell(), id.impl());
  }
}
}

JSObject* JSTerminal::createConstructor(VM& vm, JSGlobalObject* globalObject, JSValue prototype)
{
  return WebCore::JSTerminalConstructor::create(vm, globalObject, WebCore::JSTerminalConstructor::createStructure(vm, globalObject, globalObject->functionPrototype()), jsCast<WebCore::JSTerminalPrototype*>(prototype));
}

JSObject* JSTerminal::createPrototype(VM& vm, JSDOMGlobalObject* globalObject)
{
    auto *structure = JSTerminalPrototype::createStructure(vm, globalObject, globalObject->objectPrototype());
    structure->setMayBePrototype(true);
    return JSTerminalPrototype::create(vm, globalObject, structure);
}

