void JSTimeout::analyzeHeap(JSCell* cell, HeapAnalyzer& analyzer)
{
    auto* thisObject = jsCast<JSTimeout*>(cell);
    if (void* wrapped = thisObject->wrapped()) {
        analyzer.setWrappedObjectForCell(cell, wrapped);
    }

    Base::analyzeHeap(cell, analyzer);
    auto& vm = thisObject->vm();

    
if (JSValue m_argumentsValue = thisObject->m_arguments.get()) {
  if (m_argumentsValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "arguments"_s);
    analyzer.analyzePropertyNameEdge(cell, m_argumentsValue.asCell(), id.impl());
  }
}
  
if (JSValue m_callbackValue = thisObject->m_callback.get()) {
  if (m_callbackValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "callback"_s);
    analyzer.analyzePropertyNameEdge(cell, m_callbackValue.asCell(), id.impl());
  }
}
  
if (JSValue m_idleTimeoutValue = thisObject->m_idleTimeout.get()) {
  if (m_idleTimeoutValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "idleTimeout"_s);
    analyzer.analyzePropertyNameEdge(cell, m_idleTimeoutValue.asCell(), id.impl());
  }
}
  
if (JSValue m_repeatValue = thisObject->m_repeat.get()) {
  if (m_repeatValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "repeat"_s);
    analyzer.analyzePropertyNameEdge(cell, m_repeatValue.asCell(), id.impl());
  }
}
  
if (JSValue m_idleStartValue = thisObject->m_idleStart.get()) {
  if (m_idleStartValue.isCell()) {
    const Identifier& id = Identifier::fromString(vm, "idleStart"_s);
    analyzer.analyzePropertyNameEdge(cell, m_idleStartValue.asCell(), id.impl());
  }
}
}

